async function fetchGoogleSheetCSV(sheetId, gid = "0") {
  const urlsToTry = [
    `https://docs.google.com/spreadsheets/d/${sheetId}/export?format=csv&gid=${gid}`,
    `https://docs.google.com/spreadsheets/d/${sheetId}/gviz/tq?tqx=out:csv&gid=${gid}`,
    `https://docs.google.com/spreadsheets/d/${sheetId}/pub?output=csv&gid=${gid}`
  ];
  let lastError = null;
  for (const url of urlsToTry) {
    try {
      const res = await fetch(url);
      if (res.ok) {
        const text = await res.text();
        if (text && String(text || "").trim().length > 0 && !text.includes("<!DOCTYPE html>")) {
          return text;
        }
      }
    } catch (err) {
      lastError = err;
    }
  }
  for (const url of urlsToTry) {
    try {
      const proxyUrl = `https://api.allorigins.win/raw?url=${encodeURIComponent(url)}`;
      const res = await fetch(proxyUrl);
      if (res.ok) {
        const text = await res.text();
        if (text && String(text || "").trim().length > 0 && !text.includes("<!DOCTYPE html>")) {
          return text;
        }
      }
    } catch (err) {
      lastError = err;
    }
  }
  throw new Error(
    "Access Denied or Sheet not found. Please make sure the Google Sheet share settings are set to 'Anyone with the link can view'."
  );
}
const getClinicBadgeColor = (clinic) => {
  if (!clinic) return "bg-white/5 text-slate-300 border-white/10";
  const lp = clinic.toLowerCase();
  if (lp.includes("dermadent"))
    return "bg-blue-500/10 text-blue-300 border-blue-500/20";
  if (lp.includes("onetouch"))
    return "bg-emerald-500/10 text-emerald-300 border-emerald-500/20";
  if (lp.includes("welltouch"))
    return "bg-rose-500/10 text-rose-300 border-rose-500/20";
  if (lp.includes("newage"))
    return "bg-amber-500/10 text-amber-300 border-amber-500/20";
  return "bg-white/5 text-slate-300 border-white/10";
};
